+    var table: [256]u32 = undefined;
+    for (0..256) |i| {
+        var crc: u32 = @intCast(i);
+        for (0..8) |_| {
+            if (crc & 1 != 0) {
+                crc = (crc >> 1) ^ 0xEDB88320;
+            } else {
+                crc >>= 1;
+            }
+        }
+        table[i] = crc;
+    }
+    break :blk table;
+};
+
+// ============================================================================
+// CRC-HQXX TABLE
+// ============================================================================
