+        for (0..8) |_| {
+            if (crc & 0x8000 != 0) {
+                crc = (crc << 1) ^ 0x1021;
+            } else {
+                crc <<= 1;
+            }
+        }
+        table[i] = crc;
+    }
+    break :blk table;
+};
